[CmdletBinding()]
param([Parameter(Mandatory=$true)][string]$Manifest,[Parameter(Mandatory=$true)][string]$Output)
$ErrorActionPreference='Stop'
$ux=Get-Content -Raw -LiteralPath (Resolve-Path -LiteralPath $Manifest) | ConvertFrom-Json
$title=(@($ux.pages)|Where-Object id -eq 'operations-dashboard').title
$nav=@($ux.shell.navigation|ForEach-Object{"<a href='#' class='nav-item'><span class='nav-icon'></span><span>$([Net.WebUtility]::HtmlEncode($_.label))</span></a>"}) -join "`n"
$html=@"
<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>$title</title>
<style>
:root{--nav:#142a43;--nav2:#0d1d30;--ink:#17263a;--muted:#607086;--line:#dfe5ec;--surface:#fff;--canvas:#f4f6f9;--brand:#176b87;--accent:#2b819a;--good:#28755b;--warn:#a86100;--bad:#b42318;--radius:12px;--shadow:0 2px 8px rgba(23,38,58,.08)}*{box-sizing:border-box}html,body{max-width:100%;overflow-x:hidden}body{margin:0;font-family:"Segoe UI",Arial,sans-serif;color:var(--ink);background:var(--canvas)}button,input{font:inherit}.shell{display:grid;grid-template-columns:248px 1fr;min-height:100vh}.sidebar{background:linear-gradient(180deg,var(--nav),var(--nav2));color:#fff;padding:24px 16px;position:sticky;top:0;height:100vh}.brand{display:flex;gap:12px;align-items:center;padding:0 10px 24px;font-weight:700;font-size:18px}.brand-mark{width:34px;height:34px;border-radius:9px;background:#38a5bd;display:grid;place-items:center}.nav-item{display:flex;align-items:center;gap:12px;color:#d9e5f0;text-decoration:none;padding:11px 12px;border-radius:8px;margin:3px 0;font-size:14px}.nav-item:first-of-type,.nav-item:hover{background:rgba(255,255,255,.11);color:#fff}.nav-icon{width:17px;height:17px;border:1.5px solid currentColor;border-radius:5px}.main{min-width:0}.topbar{height:72px;background:#fff;border-bottom:1px solid var(--line);display:flex;align-items:center;gap:16px;padding:0 28px;position:sticky;top:0;z-index:2}.search{flex:1;max-width:620px;min-width:0;border:1px solid #cbd5df;border-radius:9px;padding:11px 14px;background:#f9fafb}.create{margin-left:auto;background:var(--brand);color:#fff;border:0;border-radius:8px;padding:11px 17px;font-weight:600;white-space:nowrap}.avatar{width:36px;height:36px;border-radius:50%;background:#d7eaf0;display:grid;place-items:center;color:var(--brand);font-weight:700}.content{padding:28px;max-width:1600px;margin:auto}.heading{display:flex;justify-content:space-between;align-items:end;margin-bottom:20px}.heading h1{font-size:28px;margin:0 0 5px}.heading p{margin:0;color:var(--muted)}.filters{display:flex;gap:8px;flex-wrap:wrap}.filter{border:1px solid #cbd5df;background:#fff;padding:8px 11px;border-radius:8px;color:#42536a}.kpis{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:16px}.card{background:var(--surface);border:1px solid var(--line);border-radius:var(--radius);box-shadow:var(--shadow)}.kpi{padding:18px}.kpi-label{font-size:13px;color:var(--muted);font-weight:600}.kpi-row{display:flex;justify-content:space-between;align-items:end;margin-top:9px}.kpi-value{font-size:30px;font-weight:700}.trend{font-size:12px;color:var(--good);background:#e9f5ef;padding:4px 7px;border-radius:99px}.trend.bad{color:var(--bad);background:#fff0ee}.grid{display:grid;grid-template-columns:1.45fr 1fr;gap:16px;margin-top:16px}.panel{padding:20px;min-width:0}.panel-head{display:flex;justify-content:space-between;align-items:center;margin-bottom:18px}.panel h2{font-size:17px;margin:0}.subtle{color:var(--muted);font-size:12px}.bars{display:grid;gap:12px}.bar-row{display:grid;grid-template-columns:90px minmax(0,1fr) 28px;gap:10px;align-items:center;font-size:13px}.track{height:10px;background:#edf1f5;border-radius:6px;overflow:hidden}.fill{height:100%;background:linear-gradient(90deg,var(--brand),#4aa8bd);border-radius:6px}.chart{height:190px;display:flex;align-items:end;gap:11px;border-bottom:1px solid #cad4df;padding:12px 8px 0;background:repeating-linear-gradient(to top,#fff 0,#fff 45px,#edf1f5 46px);min-width:0}.column{flex:1;background:linear-gradient(180deg,#55afc2,var(--brand));border-radius:5px 5px 0 0;min-width:8px;position:relative}.column span{position:absolute;top:-20px;width:100%;text-align:center;font-size:11px;color:var(--muted)}.table-card{margin-top:16px;overflow:hidden}.table-head{display:flex;justify-content:space-between;align-items:center;padding:18px 20px;border-bottom:1px solid var(--line)}table{width:100%;border-collapse:collapse;font-size:13px}th{text-align:left;color:var(--muted);font-size:11px;text-transform:uppercase;letter-spacing:.04em;background:#f8fafc}th,td{padding:13px 16px;border-bottom:1px solid #edf1f5}.case-link{color:var(--brand);font-weight:700}.badge{display:inline-flex;align-items:center;gap:5px;border-radius:99px;padding:4px 8px;font-size:11px;font-weight:650}.badge:before{content:"";width:6px;height:6px;background:currentColor;border-radius:50%}.risk-high,.sla-breach{color:var(--bad);background:#fff0ee}.risk-med,.sla-risk{color:var(--warn);background:#fff5e6}.risk-low{color:var(--good);background:#e9f5ef}.owner{display:flex;align-items:center;gap:7px}.owner i{width:25px;height:25px;border-radius:50%;background:#dce8f2;display:inline-grid;place-items:center;font-style:normal;font-size:10px}.mobile-title{display:none}
@media(max-width:980px){.shell{grid-template-columns:76px 1fr}.sidebar{padding:20px 10px}.brand span,.nav-item span:not(.nav-icon){display:none}.brand{padding:0 10px 22px}.nav-item{justify-content:center}.kpis{grid-template-columns:repeat(2,1fr)}.grid{grid-template-columns:1fr}.content{padding:22px}.topbar{padding:0 20px}}
@media(max-width:600px){.shell{display:block}.sidebar{display:none}.topbar{height:auto;padding:12px 14px;gap:10px;flex-wrap:wrap}.mobile-title{display:block;font-weight:700}.avatar{display:none}.search{order:3;flex:1 0 100%;width:100%;max-width:none}.create{margin-left:auto;padding:9px 11px;font-size:0}.create:after{content:"+ New";font-size:14px}.content,.grid,.kpis{min-width:0}.content{padding:16px;width:100%}.heading{align-items:start}.heading h1{font-size:23px}.filters{display:none}.kpis{grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}.kpi{padding:14px;min-width:0}.kpi-label{white-space:normal}.kpi-value{font-size:25px}.grid{gap:10px;margin-top:10px}.panel{padding:16px;width:100%;overflow:hidden}.panel-head .subtle{display:none}.bar-row{grid-template-columns:90px minmax(0,1fr) 22px}.chart{gap:7px;width:100%}.table-card{margin-top:10px;max-width:100%;overflow-x:auto}table{min-width:720px}.hide-mobile{display:none}}
</style></head><body><div class="shell"><aside class="sidebar"><div class="brand"><div class="brand-mark">Q</div><span>Quality Hub</span></div>$nav</aside><main class="main"><header class="topbar"><span class="mobile-title">Quality Hub</span><input class="search" aria-label="Search" placeholder="Search case, supplier, part or lot…"><button class="create">+ New Nonconformance</button><div class="avatar">AM</div></header><div class="content"><section class="heading"><div><h1>$title</h1><p>Tuesday, 21 July · Live operational position</p></div><div class="filters"><button class="filter">All sites ▾</button><button class="filter">Last 90 days ▾</button></div></section><section class="kpis"><article class="card kpi"><div class="kpi-label">Open cases</div><div class="kpi-row"><div class="kpi-value">47</div><span class="trend">↓ 8%</span></div></article><article class="card kpi"><div class="kpi-label">SLA at risk</div><div class="kpi-row"><div class="kpi-value">8</div><span class="trend bad">3 urgent</span></div></article><article class="card kpi"><div class="kpi-label">Overdue actions</div><div class="kpi-row"><div class="kpi-value">12</div><span class="trend bad">↑ 2</span></div></article><article class="card kpi"><div class="kpi-label">High-risk cases</div><div class="kpi-row"><div class="kpi-value">5</div><span class="trend">↓ 1</span></div></article></section><section class="grid"><article class="card panel"><div class="panel-head"><h2>Open cases by stage</h2><span class="subtle">Select a stage to view cases</span></div><div class="bars"><div class="bar-row"><span>Capture</span><div class="track"><div class="fill" style="width:38%"></div></div><b>7</b></div><div class="bar-row"><span>Investigate</span><div class="track"><div class="fill" style="width:88%"></div></div><b>18</b></div><div class="bar-row"><span>Decide</span><div class="track"><div class="fill" style="width:55%"></div></div><b>10</b></div><div class="bar-row"><span>Resolve</span><div class="track"><div class="fill" style="width:46%"></div></div><b>8</b></div><div class="bar-row"><span>Validate</span><div class="track"><div class="fill" style="width:22%"></div></div><b>4</b></div></div></article><article class="card panel"><div class="panel-head"><h2>Case intake trend</h2><span class="subtle">Previous 7 months</span></div><div class="chart"><div class="column" style="height:52%"><span>18</span></div><div class="column" style="height:64%"><span>22</span></div><div class="column" style="height:46%"><span>16</span></div><div class="column" style="height:78%"><span>27</span></div><div class="column" style="height:69%"><span>24</span></div><div class="column" style="height:88%"><span>31</span></div><div class="column" style="height:58%"><span>20</span></div></div></article></section><section class="card table-card"><div class="table-head"><div><h2 style="margin:0;font-size:17px">Urgent work</h2><span class="subtle">Cases requiring intervention</span></div><button class="filter">View all cases</button></div><table><thead><tr><th>Case</th><th>Supplier</th><th>Stage</th><th>Risk</th><th>Owner</th><th>SLA</th></tr></thead><tbody><tr><td><span class="case-link">SNC-2026-0142</span><br>Seal failure on incoming valve</td><td>Northstar Components</td><td>Investigate</td><td><span class="badge risk-high">High</span></td><td><span class="owner"><i>AK</i>A. Khan</span></td><td><span class="badge sla-breach">Breached 2d</span></td></tr><tr><td><span class="case-link">SNC-2026-0137</span><br>Incorrect coating thickness</td><td>Vertex Metals</td><td>Decide</td><td><span class="badge risk-med">Medium</span></td><td><span class="owner"><i>LM</i>L. Morgan</span></td><td><span class="badge sla-risk">Due today</span></td></tr><tr><td><span class="case-link">SNC-2026-0129</span><br>Contamination in packaging lot</td><td>Alpine Packaging</td><td>Resolve</td><td><span class="badge risk-high">High</span></td><td><span class="owner"><i>RS</i>R. Singh</span></td><td><span class="badge sla-risk">9h left</span></td></tr></tbody></table></section></div></main></div></body></html>
"@
$destination=[IO.Path]::GetFullPath($Output);$parent=Split-Path -Parent $destination;if(-not(Test-Path $parent)){New-Item -ItemType Directory -Path $parent|Out-Null};$html|Set-Content -Encoding utf8 -LiteralPath $destination
Write-Output "Rendered case UX reference: $destination"
